// ExTauri LiveView Hook — Bridge between Phoenix LiveView and Tauri APIs
// Generated by ExTauri. See ExTauri.Hook for documentation.

function isTauri() {
  return window.__TAURI__ !== undefined;
}

// Allowlist of valid commands to prevent arbitrary command injection
const ALLOWED_COMMANDS = new Set([
  "notification", "clipboard_write", "clipboard_read",
  "dialog_open", "dialog_save", "dialog_message",
  "os_info", "fs_read", "fs_write", "fs_exists",
  "fs_readdir", "fs_remove", "fs_mkdir",
  "shell_open", "shell_exec", "invoke"
]);

async function execCommand(command, payload) {
  if (!isTauri()) {
    throw new Error("Not running in Tauri — commands are only available in the desktop app");
  }

  if (!ALLOWED_COMMANDS.has(command)) {
    throw new Error(`Blocked unknown Tauri command: ${command}`);
  }

  switch (command) {
    case "notification": {
      const { sendNotification, isPermissionGranted, requestPermission } =
        await import("@tauri-apps/plugin-notification");
      let permitted = await isPermissionGranted();
      if (!permitted) {
        const permission = await requestPermission();
        permitted = permission === "granted";
      }
      if (permitted) {
        sendNotification(payload);
        return { status: "sent" };
      }
      return { status: "denied" };
    }

    case "clipboard_write": {
      const { writeText } = await import("@tauri-apps/plugin-clipboard-manager");
      await writeText(payload.text);
      return { status: "ok" };
    }

    case "clipboard_read": {
      const { readText } = await import("@tauri-apps/plugin-clipboard-manager");
      const text = await readText();
      return { text };
    }

    case "dialog_open": {
      const { open } = await import("@tauri-apps/plugin-dialog");
      const result = await open(payload);
      return { path: result };
    }

    case "dialog_save": {
      const { save } = await import("@tauri-apps/plugin-dialog");
      const result = await save(payload);
      return { path: result };
    }

    case "dialog_message": {
      const { message, ask, confirm } = await import("@tauri-apps/plugin-dialog");
      if (payload.type === "ask") {
        const result = await ask(payload.message, payload);
        return { result };
      } else if (payload.type === "confirm") {
        const result = await confirm(payload.message, payload);
        return { result };
      } else {
        await message(payload.message, payload);
        return { status: "ok" };
      }
    }

    case "os_info": {
      const { platform, arch, version, type: osType, locale } =
        await import("@tauri-apps/plugin-os");
      return {
        platform: platform(),
        arch: arch(),
        version: version(),
        os_type: osType(),
        locale: await locale(),
      };
    }

    case "fs_read": {
      const { readTextFile } = await import("@tauri-apps/plugin-fs");
      const opts = {};
      if (payload.baseDir) opts.baseDir = payload.baseDir;
      const contents = await readTextFile(payload.path, opts);
      return { contents };
    }

    case "fs_write": {
      const { writeTextFile } = await import("@tauri-apps/plugin-fs");
      const opts = {};
      if (payload.baseDir) opts.baseDir = payload.baseDir;
      if (payload.append) opts.append = true;
      await writeTextFile(payload.path, payload.contents, opts);
      return { status: "ok" };
    }

    case "fs_exists": {
      const { exists } = await import("@tauri-apps/plugin-fs");
      const opts = {};
      if (payload.baseDir) opts.baseDir = payload.baseDir;
      const result = await exists(payload.path, opts);
      return { exists: result };
    }

    case "fs_readdir": {
      const { readDir } = await import("@tauri-apps/plugin-fs");
      const opts = {};
      if (payload.baseDir) opts.baseDir = payload.baseDir;
      const entries = await readDir(payload.path, opts);
      return { entries };
    }

    case "fs_remove": {
      const { remove } = await import("@tauri-apps/plugin-fs");
      const opts = {};
      if (payload.baseDir) opts.baseDir = payload.baseDir;
      await remove(payload.path, opts);
      return { status: "ok" };
    }

    case "fs_mkdir": {
      const { mkdir } = await import("@tauri-apps/plugin-fs");
      const opts = { recursive: payload.recursive !== false };
      if (payload.baseDir) opts.baseDir = payload.baseDir;
      await mkdir(payload.path, opts);
      return { status: "ok" };
    }

    case "shell_open": {
      const { open } = await import("@tauri-apps/plugin-shell");
      await open(payload.url);
      return { status: "ok" };
    }

    case "shell_exec": {
      const { Command } = await import("@tauri-apps/plugin-shell");
      const cmd = Command.create(payload.program, payload.args || []);
      const output = await cmd.execute();
      return { stdout: output.stdout, stderr: output.stderr, code: output.code };
    }

    case "invoke": {
      const { invoke } = await import("@tauri-apps/api/core");
      const result = await invoke(payload.cmd, payload.args || {});
      return { result };
    }

    default:
      throw new Error(`Unknown Tauri command: ${command}`);
  }
}

export const TauriHook = {
  mounted() {
    this._setupCommandHandler();
  },

  // Re-attach the event handler when LiveView reconnects after a disconnect.
  // Without this, commands pushed after reconnection would be silently dropped.
  reconnected() {
    this._setupCommandHandler();
  },

  // Clean up any in-flight state when the hook element is removed from the DOM.
  destroyed() {
    this._destroyed = true;
  },

  _setupCommandHandler() {
    this._destroyed = false;

    this.handleEvent("tauri_command", async ({ ref, command, payload }) => {
      // Guard against responses being pushed after the hook was destroyed
      // (e.g., a slow dialog resolved after navigation).
      if (this._destroyed) return;

      try {
        const result = await execCommand(command, payload);
        if (!this._destroyed) {
          this.pushEvent("tauri_response", { ref, command, ...result });
        }
      } catch (error) {
        if (!this._destroyed) {
          this.pushEvent("tauri_error", {
            ref,
            command,
            error: error.message || String(error),
          });
        }
      }
    });
  },
};
